+#[derive(Debug, Clone, PartialEq, Eq)]
+struct ParserTelemetrySample {
+    duration_us: u64,
+    source_bytes: u64,
+    token_count: u64,
+    allocation_estimate: u64,
+    peak_rss_bytes: u64,
